INSERT INTO `wp_posts` VALUES("459", "1", "2017-01-19 19:57:37", "2017-01-19 16:57:37", "Lillian, a BCom (Marketing) graduate from the University of Nairobi, has over 20 years experience ininsurance broking. She worked in senior positions at Alexander Forbes Insurance Brokers and as Broking,Business Development and Strategy Manager at Starlit Insurance Brokers. Lillian has virtually handled all themajor insurance risks in Kenya, is highly technical, and has a tremendous commitment to staff, and focus on customer care.", "Lillian Kwimba", "", "publish", "closed", "closed", "", "lillian-kwimba", "", "", "2017-01-19 22:27:34", "2017-01-19 19:27:34", "", "0", "http://royalassociates.co.ke/?post_type=team&#038;p=459", "0", "team", "", "0");
