INSERT INTO `wp_posts` VALUES("499", "1", "2017-01-20 10:07:31", "2017-01-20 07:07:31", "Royal Associates Insurance Brokers is one of East Africa’s fastest growing insurance broking firms with the clout and connections of a big player. We offer tailored insurance risk solutions that meet our clients’ unique needs and are aligned to industry best practice.\r\n<h2>Our Core Values</h2>", "About Us", "Royal Associates Insurance Brokers is one of East Africa’s fastest growing insurance broking firms with the clout and connections of a big player. We offer tailored insurance risk solutions that meet our clients’ unique needs and are aligned to industry best practice.", "inherit", "closed", "closed", "", "103-revision-v1", "", "", "2017-01-20 10:07:31", "2017-01-20 07:07:31", "", "103", "http://royalassociates.co.ke/blog/103-revision-v1/", "0", "revision", "", "0");
INSERT INTO `wp_posts` VALUES("500", "1", "2017-01-20 10:14:56", "2017-01-20 07:14:56", "Royal Associates Insurance Brokers is one of East Africa’s fastest growing insurance broking firms with the clout and connections of a big player. We offer tailored insurance risk solutions that meet our clients’ unique needs and are aligned to industry best practice.\r\n<h2>Our Core Values</h2>\r\n<ul class=\"OurCoreValues\">\r\n<li>\r\n<h3>Passion</h3>\r\n<p>We love what we do and we are deeply passionate about it. We have fun doing it.</p>\r\n</li>\r\n<li>\r\n<h3>Trust</h3>\r\n<p>We will build meaningful win-win relationships with our staff and our partners. We will relate with people in a way that is authentic and true.</p>\r\n</li>\r\n<li>\r\n<h3>Wow Service</h3>\r\n<p>We will delight our customers by always listening to them and giving them the best advice, care, and support.</p>\r\n</li>\r\n<li>\r\n<h3>Learning & Innovation</h3>\r\n<p>We are a learning organisation. We will challenge prevailing assumptions and commit to the search and discovery of better and practical solutions.</p>\r\n</li>\r\n<li>\r\n<h3>Excellence</h3>\r\n<p>We are committed to being the best we can be. We will create better ways of doing things and set new standards in our industry.</p></li>\r\n</ul>", "About Us", "Royal Associates Insurance Brokers is one of East Africa’s fastest growing insurance broking firms with the clout and connections of a big player. We offer tailored insurance risk solutions that meet our clients’ unique needs and are aligned to industry best practice.", "inherit", "closed", "closed", "", "103-revision-v1", "", "", "2017-01-20 10:14:56", "2017-01-20 07:14:56", "", "103", "http://royalassociates.co.ke/blog/103-revision-v1/", "0", "revision", "", "0");
