INSERT INTO `wp_posts` VALUES("520", "1", "2017-01-20 13:32:07", "2017-01-20 10:32:07", "Royal Associates Insurance Brokers is one of East Africa’s fastest growing insurance broking firms with the clout and connections of a big player. We offer tailored insurance risk solutions that meet our clients’ unique needs and are aligned to industry best practice.\r\n<div class=\"group BranD\">\r\n<div class=\"col c6\">\r\n<h2>Our Vision</h2>\r\nWe leverage on technology and provide unique insurance risk solutions. We are committed to becoming Africa’s leading brokerage.\r\n</div>\r\n<div class=\"col c6 Omega\">\r\n<h2>Our Mission</h2>\r\nWe are dedicated to providing the best advice, and to delivering first class care and support, to ensure that our clients always realize first-class coverage.\r\n</div>\r\n<div class=\"col c6\">\r\n<h2>Our Strength</h2>\r\nOur strength lies in our people. Our team is a partnership of highly qualified and talented professionals who are committed to providing clients with expert advice, and to serving them with purpose and dedication.\r\n</div>\r\n<div class=\"col c6 Omega\">\r\n<h2>Our Philosophy</h2>\r\nWe venture into unknown waters and embrace new ideas. Through creativity and innovation, we design and structure unique risk and financial solutions that offer the best coverage possible for our clients.\r\nWe are a truly listening partner, endeavoring to understand our clients’ unique insurance needs, and seeking to come up with practical and innovative solutions to meet those needs.\r\n</div>\r\n</div>\r\n", "About Us", "Royal Associates Insurance Brokers is one of East Africa’s fastest growing insurance broking firms with the clout and connections of a big player. We offer tailored insurance risk solutions that meet our clients’ unique needs and are aligned to industry best practice.", "inherit", "closed", "closed", "", "103-revision-v1", "", "", "2017-01-20 13:32:07", "2017-01-20 10:32:07", "", "103", "http://royalassociates.co.ke/blog/103-revision-v1/", "0", "revision", "", "0");
