INSERT INTO `wp_posts` VALUES("568", "1", "2017-01-25 10:04:17", "2017-01-25 07:04:17", "Our Royal Motor Private Policy cover is aimed at proving unique motoring risks solutions to our clients. Our innovative policy provides tailor made cover to protect the motorists against the risks of theft, accidental loss, of or damage to the motor vehicles. The cover also includes legal liability to third parties arising from use of the vehicle. This policy covers vehicles used for Social, Domestic and Pleasure purposes and in connection with the insured business or profession.\r\n\r\nSome of the key features of our policies include:\r\n<ol>\r\n<li>Enhanced Third party property damage limit</li>\r\n<li>High limit for Windscreen cover that includes Wing mirrors</li>\r\n<li>Enhanced limits on Towing charges, Medical Aid and Radio cassette/ Music system cover</li>\r\n<li>Agreed value cover</li>\r\n<li>Free valuations</li>\r\n<li>Free personal Accident cover</li>\r\n<li>Capped excess</li>\r\n<li>No blame no excess</li>\r\n<li>Courtesy car – Car of Similar make/ Model</li>\r\n<li>Compensation for forced ATM withdrawals following hi-jack</li>\r\n<li>Excess protector cover</li>\r\n<li>24 hour road rescue /Assistance</li>\r\n<li>Emergency accommodation cover in case of an accident</li>\r\n</ol>", "Private Motor Insurance", "", "publish", "closed", "closed", "", "motor-insurance-kenya", "", "", "2017-02-17 11:08:58", "2017-02-17 08:08:58", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=568", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("569", "1", "2017-01-25 11:33:36", "2017-01-25 08:33:36", "Accidents are not good! Can you imagine the kind of interruptions this kind of unwanted misfortunes courses? Everyone is exposed to a wide spectrum of misfortune through their working environment, travelling, sports, war, terrorist attacks crimes etc. One of the major impacts of these unwelcome events is interruption in life both for individual and their loved ones. At Royal Associates Insurance, we have the necessary expertise to arrange for a focused and appropriate protection against these interruptions. Our Royal Income Protector Policy provides security to individuals/families or groups and provides compensation for death, permanent disablement, temporary loss of income due to disablement and medical expenses arising from an accident.\r\n\r\nSome of the key free addons on the cover (following an accident) include:\r\n<ol>\r\n<li>Free last expense cover</li>\r\n<li>Free Ambulance assistance</li>\r\n<li>Free Dental cover</li>\r\n<li>Free Optical cover</li>\r\n<li>Free Wheel chair assistance</li>\r\n<li>Free Local evacuation</li>\r\n<li>Free hearing aids</li>\r\n<li>Free Rehabilitation cover</li>\r\n<li>Free artificial appliances</li>\r\n</ol>\r\n\r\n", "Accident Cover", "", "publish", "closed", "closed", "", "accident-cover", "", "", "2017-02-17 11:10:01", "2017-02-17 08:10:01", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=569", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("570", "1", "2017-01-25 11:23:35", "2017-01-25 08:23:35", "Home owners insurance is part of our property line insurances and our team of experts will be able to design and place an appropriate insurance programme that suits your underlying needs. This policy will protect private home owners against loss or damage to property and liabilities arising out of ownership or occupation of the property \r\n\r\nOur home owners Insurance uniquely combine other personal insurances to form a package that offers a total protection and peace of mind. These include:\r\n<ul>\r\n<li>Loss or damage to the residential property( buildings)Home owners contents</li>\r\n<li>Loss of rental value or expenses for alternative accommodation following a loss/Damage to property</li>\r\n<li>Portable personal items and those highly susceptible to accidental damage</li>\r\n<li>Loss or damage to guest effects</li>\r\n<li>Compensation for accidental death or disability to the insured’s domestic servants in line with the workers Injury benefits Act of 2007. This cover includes Medical expenses of upto Kshs.100,000/- and a last expense of upto Kshs.30,000/-</li>\r\n<li>Emergence medical expenses cover following an accident in the residential property,\r\nEnhanced owners and /or Occupiers Liability Insurance cover limits</li>\r\n<li>Our Royal Home policy has a Unique in built Personal liability cover with an enhanced Limit.</li>\r\n</ul>", "Domestic Package (Royal Home Owners Insurance)", "", "publish", "closed", "closed", "", "domestic-package-royal-home", "", "", "2017-02-17 11:13:01", "2017-02-17 08:13:01", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=570", "0", "product", "", "0");
