INSERT INTO `wp_posts` VALUES("573", "1", "2017-01-25 12:57:56", "2017-01-25 09:57:56", "", "personal accident insurance", "", "inherit", "open", "closed", "", "accident-insurance", "", "", "2017-01-25 12:59:29", "2017-01-25 09:59:29", "", "569", "http://royalassociates.co.ke/wp-content/uploads/2017/01/accident-insurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("574", "1", "2017-02-01 13:07:43", "2017-02-01 10:07:43", "Royal Motor commercial/General Cartage Policy cover is aimed at proving unique motoring risks solutions to our clients. Our innovative policy provides tailor made cover to protect the motorists against the risks of  theft, accidental loss of or damage to the motor vehicles. The cover also includes legal liability to third parties arising from use of the vehicle. This policy covers vehicles used for own use and commercial purposes. \r\n\r\nClass of vehicles covered under this policy include Pick-ups, Lorries, Trucks, Prime movers, Tractors, Tours vehicles & Taxis.  \r\n\r\nAt Royal Associates Insurance, we appreciate that delays in sorting out repairs for the Motor commercial vehicles could lead to immense loss of business and we have therefore made appropriate arrangements for the assessment and repair authority to be issued within 48 hours. Our Royal Motor Commercial policy carries an exceptionally high authorised repair limit to necessitate automatic repairs in respect of not so big damages. Our Motor commercial policy also carries a unique “ Cash benefit “ rider which the Insured could use to offset the Bank interest cost  accruing during the period the motor vehicle is undergoing repairs covered by the policy.\r\n\r\nLike the motor private policy, our Motor Commercial policy also carries unique riders and some of the key ones includes the following:\r\n\r\n<ol>\r\n<li>Enhanced Third party property damage limit</li>\r\n<li>High limit for Windscreen cover that includes Wing mirrors</li>\r\n<li>Enhanced limits on Towing charges, Medical Aid and Radio cassette/ Music system cover</li>\r\n<li>Agreed value cover</li>\r\n<li>Free valuations</li>\r\n<li>Free personal Accident cover</li>\r\n<li>Capped excess</li>\r\n<li>No blame no excess</li>\r\n<li>Loss of use - Cash Benefit</li>\r\n<li>Compensation for forced ATM withdrawals following hi-jack</li>\r\n<li>Excess protector cover</li>\r\n<li>24 hour road rescue /Assistance</li>\r\n<li>Emergency accommodation cover in case of an accident</li>\r\n</ol>\r\n", "Commercial General Cartage Motor Insurance", "", "publish", "closed", "closed", "", "commercial-general-cartage-motor-insurance", "", "", "2017-02-17 11:08:10", "2017-02-17 08:08:10", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=574", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("575", "1", "2017-01-25 13:07:03", "2017-01-25 10:07:03", "", "Motor Commercial Insurance kenya", "", "inherit", "open", "closed", "", "motor-commercial-insurance-kenya", "", "", "2017-01-25 13:07:34", "2017-01-25 10:07:34", "", "574", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Motor-Commercial-Insurance-kenya.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("576", "1", "2017-02-17 11:07:57", "2017-02-17 08:07:57", "Royal Motor commercial/General Cartage Policy cover is aimed at proving unique motoring risks solutions to our clients. Our innovative policy provides tailor made cover to protect the motorists against the risks of  theft, accidental loss of or damage to the motor vehicles. The cover also includes legal liability to third parties arising from use of the vehicle. This policy covers vehicles used for own use and commercial purposes. \n\nClass of vehicles covered under this policy include Pick-ups, Lorries, Trucks, Prime movers, Tractors, Tours vehicles & Taxis.  \n\nAt Royal Associates Insurance, we appreciate that delays in sorting out repairs for the Motor commercial vehicles could lead to immense loss of business and we have therefore made appropriate arrangements for the assessment and repair authority to be issued within 48 hours. Our Star Motor Commercial policy carries an exceptionally high authorised repair limit to necessitate automatic repairs in respect of not so big damages. Our Motor commercial policy also carries a unique “ Cash benefit “ rider which the Insured could use to offset the Bank interest cost  accruing during the period the motor vehicle is undergoing repairs covered by the policy.\n\nLike the motor private policy, our Motor Commercial policy also carries unique riders and some of the key ones includes the following:\n\n<ol>\n<li>Enhanced Third party property damage limit</li>\n<li>High limit for Windscreen cover that includes Wing mirrors</li>\n<li>Enhanced limits on Towing charges, Medical Aid and Radio cassette/ Music system cover</li>\n<li>Agreed value cover</li>\n<li>Free valuations</li>\n<li>Free personal Accident cover</li>\n<li>Capped excess</li>\n<li>No blame no excess</li>\n<li>Loss of use - Cash Benefit</li>\n<li>Compensation for forced ATM withdrawals following hi-jack</li>\n<li>Excess protector cover</li>\n<li>24 hour road rescue /Assistance</li>\n<li>Emergency accommodation cover in case of an accident</li>\n</ol>\n", "Commercial General Cartage Motor Insurance", "", "inherit", "closed", "closed", "", "574-autosave-v1", "", "", "2017-02-17 11:07:57", "2017-02-17 08:07:57", "", "574", "http://royalassociates.co.ke/blog/574-autosave-v1/", "0", "revision", "", "0");
INSERT INTO `wp_posts` VALUES("577", "1", "2017-01-25 13:22:46", "2017-01-25 10:22:46", "", "Private motor insurance kenya", "", "inherit", "open", "closed", "", "private-motor-insurance-kenya", "", "", "2017-01-25 13:22:55", "2017-01-25 10:22:55", "", "375", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Private-motor-insurance-kenya.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("579", "1", "2017-01-25 13:39:00", "2017-01-25 10:39:00", "", "Private motor insurance", "", "inherit", "open", "closed", "", "private-motor-insurance-2", "", "", "2017-01-25 13:40:18", "2017-01-25 10:40:18", "", "375", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Private-motor-insurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("580", "1", "2017-01-25 16:33:14", "2017-01-25 13:33:14", "At Royal Associates Insurance, we have a pool of professionals experienced in structuring various policies to cater for various clients’ specific requirements. We do reviews on a regular basis to take advantage of developments in the insurance market as they occur.\r\n\r\nWe make appropriate improvements in the scope of cover in order to make our policies cost effective and dispute free in the event of a claim. \r\nThese includes:\r\n<ol>\r\n<li>Restructuring the policies,\r\n<li>Including all the relevant extensive clauses</li>\r\n<li>Reviewing the premium rating structure</li>\r\n</ol>\r\n \r\nWe ensure that the warranties applying under each of the policies do not unreasonably prejudice your protection.\r\n", "Property Insurance", "", "publish", "closed", "closed", "", "property-insurance", "", "", "2017-05-15 21:41:18", "2017-05-15 18:41:18", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=580", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("581", "1", "2017-01-25 14:32:14", "2017-01-25 11:32:14", "Legal suits as a result of work places injuries are also becoming a phenomenon. Compensation of injured employees under the WIBA does not prevent them from pursuing a further claim legally under the common law. These type of suits can be a nuisance and very expensive to defend!\r\nAt Royal Associates Insurance, we offer an adequate solution in form of Employers liability cover and your only requirement is to forward all the demand letters and court summons un answered for the insures’ appointed legal experts to defend on your behalf.\r\n", "Employers Liability Insurance", "", "publish", "closed", "closed", "", "employers-liability-insurance", "", "", "2017-02-03 11:55:18", "2017-02-03 08:55:18", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=581", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("583", "1", "2017-01-25 16:32:44", "2017-01-25 13:32:44", "", "Property Insurance Kenya", "", "inherit", "open", "closed", "", "property-insurance-kenya", "", "", "2017-01-25 16:33:06", "2017-01-25 13:33:06", "", "580", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Property-Insurance-Kenya.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("584", "1", "2017-01-25 17:11:53", "2017-01-25 14:11:53", "The basic Fire policy provides indemnity/cover against loss or damage to insured property, caused by fire, lightning and explosion. However, the policy can also be extended to cover riots, strike, malicious damage, storm, earthquake, impact by vehicles, aircraft and other aerial devices, subterranean fire, spontaneous combustion, explosion of industrial boilers and economizers, flooding, water damage due to bursting or overflowing of water tanks, apparatus, and pipes among others.  \r\n\r\nThis insurance covers assets such as buildings, plant and machinery, stock, furniture fixtures and fittings and office equipment.\r\n\r\nWe will arrange a suitable fire and perils policy with appropriate extensive clauses for maximum protection at the most appropriate cost.\r\n\r\n<h2>Fire Business Interruption cover</h2>\r\n\r\nFollowing an unwelcome occurrence of fire or an operation of any of the special perils insured,   there will definitely be interruption in the business. At Royal Associates Insurance Brokers , we are highly experienced and our pool of professionals will arrange an appropriate policy to provide coverage against loss of profit due to reduction in turn over and increased cost of working or additional expenses incurred to prevent further reduction in turn over. This policy will be taken along side Fire and perils policy.\r\n\r\nWe will structure this policy appropriately to make it cost effective  at the widest scope possible.\r\n", "Fire Perils Insurance", "", "publish", "closed", "closed", "", "fire-perils-insurance", "", "", "2017-01-25 22:16:33", "2017-01-25 19:16:33", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=584", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("586", "1", "2017-01-25 22:09:40", "2017-01-25 19:09:40", "", "Fire and Perils Insurance", "", "inherit", "open", "closed", "", "fire-and-perils-insurance", "", "", "2017-01-25 22:16:30", "2017-01-25 19:16:30", "", "584", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Fire-and-Perils-Insurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("587", "1", "2017-01-25 22:59:20", "2017-01-25 19:59:20", "Burglaries or theft at commercial premises are on increase and the importance of an adequate cover cannot be over emphasised. Burglary cover falls under our property insurance line and as mentioned in the opening section, we will use our expertise to structure an ideal policy to cover your specific requirements.\r\n\r\nWe will negotiate for the right rating structure with a factor on an ideal first loss level de4pending on the level of exposure.\r\n\r\nWe will review the policy to ensure that the warranties and restrictions do not unnecessarily prejudice your protection.\r\n", "Burglary", "", "publish", "closed", "closed", "", "burglary", "", "", "2017-01-25 22:59:20", "2017-01-25 19:59:20", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=587", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("588", "1", "2017-01-25 22:59:02", "2017-01-25 19:59:02", "", "burglary insurance", "", "inherit", "open", "closed", "", "burglary-insurance", "", "", "2017-01-25 22:59:17", "2017-01-25 19:59:17", "", "587", "http://royalassociates.co.ke/wp-content/uploads/2017/01/burglary-insurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("589", "1", "2017-01-25 23:27:24", "2017-01-25 20:27:24", "As the name suggests, all risks policy provides cover against all risks not specifically excluded.\r\n\r\nOur professionals will arrange for an ideal cover at the most appropriate coste. We will scrutinise the warranties and restrictions to ensure that your protection is not unnecessary prejudiced. The cover will carry all the necessary extensive clauses to ensure that there is no gap in coverage. \r\n\r\n Since this policy excludes loss or damage following electrical or mechanical derangement, we highly recommend an isolation of all electronic equipment items to be covered under an appropriate Electronic equipment policy. \r\n", "All Risk Insurance", "", "publish", "closed", "closed", "", "all-risk-insurance", "", "", "2017-01-25 23:27:24", "2017-01-25 20:27:24", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=589", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("590", "1", "2017-01-25 23:27:10", "2017-01-25 20:27:10", "", "All risk insurance", "", "inherit", "open", "closed", "", "all-risk-insurance", "", "", "2017-01-25 23:27:21", "2017-01-25 20:27:21", "", "589", "http://royalassociates.co.ke/wp-content/uploads/2017/01/All-risk-insurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("591", "1", "2017-01-26 00:05:51", "2017-01-25 21:05:51", "This policy provides coverage to electronic equipment including computers against sudden and unforeseen physical damage to the equipment in a manner necessitating repair or replacement. Electronic equipment constitutes all electrical equipment that consumes low electrical current. Cover includes mechanical or electrical breakdown, faulty materials, faulty design, lightning and over voltages.\r\n\r\nThe Electronic Insurance covers also extends to cover:\r\n<ol>\r\n<li>Restoration of data ie reprogramming the equipment and reinstalling file</li>\r\n<li>Increase Costs ie Hire of replacement equipment, payment of overtime to staff.</li>\r\n</ol>\r\n", "Electronic Insurance", "", "publish", "closed", "closed", "", "electronic-insurance", "", "", "2017-01-26 00:05:51", "2017-01-25 21:05:51", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=591", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("592", "1", "2017-01-26 00:05:14", "2017-01-25 21:05:14", "", "electronics insurance", "", "inherit", "open", "closed", "", "electronics-insurance", "", "", "2017-01-26 00:05:42", "2017-01-25 21:05:42", "", "591", "http://royalassociates.co.ke/wp-content/uploads/2017/01/electronics-insurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("593", "1", "2017-01-26 00:11:15", "2017-01-25 21:11:15", "For large Industrial operators with machinery and equipments highly susceptible to breakdown, it will be ideal to take an Industrial All Risks cover in place of the traditional Fire and perils and fire Business interruption and, burglary. This is an insurance package which mainly incorporates Fire & Allied Perils, Burglary, Accidental damage and Business Interruption and it provides indemnity to the property insured against any loss or damage from any cause not excluded by the policy\r\n\r\nHowever, the policy carries higher deductibles and therefore one needs to strike a balance before settling on the ideal cover.\r\n\r\nAt Royal Associates Insurance Brokers , our experienced team of professionals will guide you appropriately on the ideal cover depending on the prevailing circumstances and the exposures.\r\n", "Industrial All Risk", "", "publish", "closed", "closed", "", "industrial-all-risk", "", "", "2017-02-06 08:24:17", "2017-02-06 05:24:17", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=593", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("597", "1", "2017-01-26 01:12:44", "2017-01-25 22:12:44", "The policy provides indemnity to the insured against loss and/or destruction/damage to glass including louvre venting, partitions and roof lights by accident or misfortune of a accidental nature.  There are options either to replace the broken glass according to description or to pay the sum equivalent to the value of the broken glass at the time of loss, destruction or breakage up to the insurance value.  Cover can be arranged for cabinet glass, display signs, fixed glass and glass partitions on premises.", "Plate Glass Insurance", "", "publish", "closed", "closed", "", "plate-glass-insurance", "", "", "2017-01-26 01:12:44", "2017-01-25 22:12:44", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=597", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("598", "1", "2017-01-26 00:57:23", "2017-01-25 21:57:23", "Indemnity/cover against loss of money and damage to safe or strong room damaged in the course of theft of money\r\nDefinition of Money:\r\nCash, bank notes, current postage and revenue stamps, gift vouchers, travellers cheques, foreign currency equivalent and any documents or instruments exchangeable for cash or goods at their face value.\r\n\r\nThis policy covers loss or damage to money by robbery or theft whilst: \r\n<ol>\r\n<li>In transit from your premises to the bank and vice versa</li> \r\n<li>In your premises during business hours</li> \r\n<li>In your premises in locked safes/strong rooms outside business hours</li> \r\n<li>In the hand of senior employees/authorised personnel of the company</li>\r\n<li>NHIF and service charge stamps and stamped cards and the contents of the franking machine</li>\r\n<li>Damage to safes and /or strong rooms</li>\r\n</ol>\r\n\r\n", "Money Insurance", "", "publish", "closed", "closed", "", "money-insurance", "", "", "2017-01-26 00:57:23", "2017-01-25 21:57:23", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=598", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("599", "1", "2017-01-26 00:56:17", "2017-01-25 21:56:17", "", "money insurance", "", "inherit", "open", "closed", "", "money-insurance-2", "", "", "2017-01-26 00:57:16", "2017-01-25 21:57:16", "", "598", "http://royalassociates.co.ke/wp-content/uploads/2017/01/money-insurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("600", "1", "2017-01-26 01:31:34", "2017-01-25 22:31:34", "All risks of loss of or damage to goods in transit anywhere in East Africa while in transit by road, rail or any inland waterway within the geographical area set out in the policy\r\nGOODS COVERED – All goods belonging to or incidental to the insured business or in their custody or control\r\n", "Goods In Transit", "", "publish", "closed", "closed", "", "goods-in-transit", "", "", "2017-02-10 20:15:27", "2017-02-10 17:15:27", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=600", "0", "product", "", "0");
