INSERT INTO `wp_posts` VALUES("602", "1", "2017-01-26 01:31:15", "2017-01-25 22:31:15", "", "Goods on Transit INsurance", "", "inherit", "open", "closed", "", "goods-on-transit-insurance", "", "", "2017-01-26 01:31:30", "2017-01-25 22:31:30", "", "600", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Goods-on-Transit-INsurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("603", "1", "2017-01-26 01:43:36", "2017-01-25 22:43:36", "Machinery Breakdown Insurance Indemnity against any unforeseen physical loss of or damage to the specified plant as a result of any cause not excluded by the policy.\r\n \r\nThe purpose of machinery insurance is: \r\n<ul>\r\n<li>To cover the cost of repairing or replacing breakdown or losses to machinery</li>\r\n</ul>\r\n", "Machinery Breakdown Insurance", "", "publish", "closed", "closed", "", "machinery-breakdown-insurance", "", "", "2017-02-10 20:07:09", "2017-02-10 17:07:09", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=603", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("604", "1", "2017-01-26 01:43:00", "2017-01-25 22:43:00", "", "machinery breakdwon insurance", "", "inherit", "open", "closed", "", "machinery-breakdwon-insurance", "", "", "2017-01-26 01:43:33", "2017-01-25 22:43:33", "", "603", "http://royalassociates.co.ke/wp-content/uploads/2017/01/machinery-breakdwon-insurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("605", "1", "2017-01-26 01:46:17", "2017-01-25 22:46:17", "We offer the best Marine cargo cover in Kenya. You have the option to either take it up on a case-by-case basis or as an annual policy.\r\n\r\nMarine Cargo Insurance policy provides indemnity against loss or damage for goods being transported by sea or air and incidental land transportation.\r\n\r\nCoverage is meant for transportation of goods or items by sea or air belonging to the insured or held in their custody or control or for which they are responsible or which they may wish to insure (including legal liabilities for general average and salvage where applicable).\r\n", "Marine Cargo", "", "publish", "closed", "closed", "", "marine-cargo", "", "", "2017-02-09 08:52:55", "2017-02-09 05:52:55", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=605", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("606", "1", "2017-01-26 01:51:47", "2017-01-25 22:51:47", "Builders are increasingly exposed to complex construction risks and they obviously need experienced experts to plan and place their risks appropriately.\r\n\r\nThe contractors all risks policy covers the construction works, construction plant and Machinery/equipment, materials on site, cost of demolition and debris removals, professional fees, Plans and designs etc.\r\n\r\nThe policy will also cover third party liabilities associated to the builders work.\r\n\r\nAt Royal Associates Insurance Brokers, we have a truck record in designing and delivering risk solutions to\r\nbuilders. We have consistently developed innovative risks solutions for some of the most famous projects in the East African region to-date.\r\n", "Contractors All Risk", "", "publish", "closed", "closed", "", "contractors-all-risk", "", "", "2017-02-10 21:03:14", "2017-02-10 18:03:14", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=606", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("608", "1", "2017-01-26 01:50:50", "2017-01-25 22:50:50", "", "machinery breakdown insurance", "", "inherit", "open", "closed", "", "machinery-breakdown-insurance-2", "", "", "2017-01-26 01:54:15", "2017-01-25 22:54:15", "", "603", "http://royalassociates.co.ke/wp-content/uploads/2017/01/machinery-breakdown-insurance.jpg", "0", "attachment", "image/jpeg", "0");
