INSERT INTO `wp_posts` VALUES("616", "1", "2017-01-26 02:16:32", "2017-01-25 23:16:32", "", "Employers Liability Insurance", "", "inherit", "open", "closed", "", "employers-liability-insurance-2", "", "", "2017-01-26 02:16:53", "2017-01-25 23:16:53", "", "0", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Employers-Liability-Insurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("617", "1", "2017-01-26 02:17:34", "2017-01-25 23:17:34", "Legal suits as a result of work places injuries are also becoming a phenomenon. Compensation of injured employees under the WIBA does not prevent them from pursuing a further claim legally under the common law. These type of suits can be a nuisance and very expensive to defend!\nAt Royal Associates Insurance, we offer an adequate solution in form of Employers liability cover and your only requirement is to forward all the demand letters and court summons un answered for the insures’ appointed legal experts to defend on your behalf.\n", "Employers Liability Insurance", "", "inherit", "closed", "closed", "", "581-autosave-v1", "", "", "2017-01-26 02:17:34", "2017-01-25 23:17:34", "", "581", "http://royalassociates.co.ke/blog/581-autosave-v1/", "0", "revision", "", "0");
INSERT INTO `wp_posts` VALUES("618", "1", "2017-01-26 08:57:56", "2017-01-26 05:57:56", "This policy provides cover for all stocks against loss or damage by fire & Allied perils and theft whilst stored in the insured’s owned or leased premises or in transit anywhere in Kenya.\r\nAll goods belonging to or incidental to the insured’s business or in their custody or transit anywhere in Kenya \r\n", "Stock Floater", "", "publish", "closed", "closed", "", "stock-floater", "", "", "2017-01-26 08:57:56", "2017-01-26 05:57:56", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=618", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("619", "1", "2017-01-26 08:57:38", "2017-01-26 05:57:38", "", "Stock Floater", "", "inherit", "open", "closed", "", "stock-floater", "", "", "2017-01-26 08:57:51", "2017-01-26 05:57:51", "", "618", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Stock-Floater.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("620", "1", "2017-01-26 09:03:24", "2017-01-26 06:03:24", "Indemnity against direct pecuniary loss resulting from fraud or dishonesty of employees. Fidelity guarantee may be bought by any organization or person who may suffer as the result of the dishonesty, failure in the loyal performance of duty or, in certain cases, the mistake of another. \r\n\r\nThe policy covers the employer against loss of money and/or stock through dishonest acts of employees.\r\n\r\nPERSONS COVERED: All employees of the Insured who handle money, stocks, stores and accounting documents\r\n", "Fidelity Guarantee", "", "publish", "closed", "closed", "", "fidelity-guarantee", "", "", "2017-01-26 09:03:24", "2017-01-26 06:03:24", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=620", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("621", "1", "2017-01-26 09:11:21", "2017-01-26 06:11:21", "The policy provides on behalf of the insured all sums which the insured becomes legally obligated to pay as damages by reason of liability arising out of any negligent act, error, mistake, or omission in the rendering of or failure to render professional services for others in the insured’s capacity as a professional. Reasonable legal defence cost is also available over and above the selected policy limit.", "Professional Indemnity", "", "publish", "closed", "closed", "", "professional-indemnity", "", "", "2017-01-26 09:25:35", "2017-01-26 06:25:35", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=621", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("624", "1", "2017-01-26 09:25:14", "2017-01-26 06:25:14", "", "Professional Indemnity", "", "inherit", "open", "closed", "", "professional-indemnity-2", "", "", "2017-01-26 09:25:31", "2017-01-26 06:25:31", "", "621", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Professional-Indemnity.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("625", "1", "2017-01-26 09:48:00", "2017-01-26 06:48:00", "Every day we are experiencing accidents in our business environment that injure, hurt or even kill third parties around us. Third party properties could also be destroyed by our business activities.\r\n\r\nOur Public/ product liability cover provides indemnity against legal liability to third parties in respect of accidental death, bodily injury and / or illness and / or loss of or damage to property incurred in the course of the Insured’s business.\r\n", "Public + Products Liability", "", "publish", "closed", "closed", "", "public-products-liability", "", "", "2017-02-03 00:41:58", "2017-02-02 21:41:58", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=625", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("626", "1", "2017-01-26 09:54:09", "2017-01-26 06:54:09", "Banks and other financial institutions face a higher level of exposure to financial loss resulting from criminal behaviour than most other institutions.  Employee theft, embezzlement, forgery, hold up and fraud are all real risks in today\'s business environment and even more so in the financial sector.  \r\n\r\nComprehensive Bankers Blanket Bond provides comprehensive cover for crime and Fidelity package designed specifically for banks and other Financial Institutions. \r\n", "Bankers Comprehensive Crime Insurance", "", "publish", "closed", "closed", "", "bankers-comprehensive-crime-insurance", "", "", "2017-01-26 09:54:09", "2017-01-26 06:54:09", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=626", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("627", "1", "2017-01-26 09:53:28", "2017-01-26 06:53:28", "", "Bankers Comprehensive Crime Insurance", "", "inherit", "open", "closed", "", "bankers-comprehensive-crime-insurance", "", "", "2017-01-26 09:53:50", "2017-01-26 06:53:50", "", "626", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Bankers-Comprehensive-Crime-Insurance.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("628", "1", "2017-01-26 10:14:50", "2017-01-26 07:14:50", "Traditional Agriculture insurance offers protection against events such as floods and storms. However, recently, a new form of agri. Insurance has been developed to offer protection against the effects of seasonal weather patterns such as temperature, rainfall or sunshine. These factors can have a major influence on corporate results and many firms publicly acknowledge this. As weather hedging becomes more commonplace, blaming the weather for poor results will become less acceptable.\r\n\r\nWeather derivatives or insurance generally provide volumetric hedge protection against a reduction in sales volumes, rather than profit. Companies interested in such protection therefore generally have a good correlation between their volumes and a weather index. The index used is most commonly temperature, but rainfall, sunshine, wind speed, or other measure may also be used.\r\n\r\nRoyal Associates Insurance Brokers  is one of the pioneers of weather risk hedging and have been involved in designing programmes in the tea agricultural sector in Kenya.\r\n\r\nWe have the rear expertise to advice organisations on all aspects of managing their weather risk, from determining and evaluating exposure,.\r\n", "Agri business & Weather Risks", "", "publish", "closed", "closed", "", "agri-business-weather-risks", "", "", "2017-01-26 10:18:08", "2017-01-26 07:18:08", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=628", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("629", "1", "2017-01-26 10:10:03", "2017-01-26 07:10:03", "", "Agri business & Weather Risks", "", "inherit", "open", "closed", "", "agri-business-weather-risks-2", "", "", "2017-01-26 10:15:17", "2017-01-26 07:15:17", "", "628", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Agri-business-Weather-Risks.jpg", "0", "attachment", "image/jpeg", "0");
