INSERT INTO `wp_posts` VALUES("631", "1", "2016-04-26 10:20:55", "2016-04-26 07:20:55", "", "Agri business & Weather Risks", "", "publish", "closed", "closed", "", "agri-business-weather-risks", "", "", "2017-02-22 15:55:11", "2017-02-22 12:55:11", "", "0", "http://royalassociates.co.ke/?post_type=slider&#038;p=631", "0", "slider", "", "0");
INSERT INTO `wp_posts` VALUES("632", "1", "2017-01-26 10:33:16", "2017-01-26 07:33:16", "Trade Credit Insurance provides indemnification for the non-payment of trade debts. Policies can be tailored according to a clients\' individual requirements, embracing not only insolvency risk on goods delivered, but also pre-delivery costs, the non-honouring of Letters of Credit, or non-delivery of pre-paid goods.\r\nWith Trade Credit Insurance in place, companies can generally extend more credit to customers whilst reducing the risk of non-payment, thereby enabling sales growth without a corresponding increase in risk. \r\n\r\nInsurance can also enable a company to secure more favourable financing terms, as insured accounts receivable may be used as collateral. The combination of robust credit management policies and procedures with properly structured Trade Credit Insurance protection can lead to higher profit margins, an enhanced balance sheet and increased shareholder value.\r\nOur team in Royal Associates Insurance Brokers  has substantial experience in structuring, placement and servicing of Trade Credit Insurance programmes for companies covering a broad spectrum of industries. \r\n", "Trade risks- Trade credit Insurance", "", "publish", "closed", "closed", "", "trade-risks-trade-credit-insurance", "", "", "2017-01-26 10:33:16", "2017-01-26 07:33:16", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=632", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("633", "1", "2017-01-26 10:33:01", "2017-01-26 07:33:01", "", "Trade risks- Trade credit Insurance", "", "inherit", "open", "closed", "", "trade-risks-trade-credit-insurance", "", "", "2017-01-26 10:33:11", "2017-01-26 07:33:11", "", "632", "http://royalassociates.co.ke/wp-content/uploads/2017/01/Trade-risks-Trade-credit-Insurance.jpg", "0", "attachment", "image/jpeg", "0");
