INSERT INTO `wp_posts` VALUES("769", "1", "2017-04-09 23:56:12", "2017-04-09 20:56:12", "At Royal Associates Health Division, we work with Individuals, SME’s and corporate employers to develop customized health benefits plans that best suits their specific needs.\r\nAmong Our Health Insurance include:\r\n<h2>Individual/ Family Health Insurance</h2>\r\n\r\nWe value your life as an individual by offering the following covers to take care of your health and that of your family:\r\n<ul>\r\n<li>Inpatient / hospitalization Cover</li>\r\n<li>Outpatient Cover</li>\r\n<li>Dental</li>\r\n<li>Optical</li>\r\n<li>Maternity</li>\r\n<li>Last Expense</li>\r\n</ul>\r\nWe realize that individuals / families have different needs and requirements and we always endeavor to give the most customized covers for our clients.\r\nAll we require to give you the most competitive quotation is your age and that of your dependants\r\n<h2>SMEs\' and Corporate Health Insurance</h2>\r\nA healthy work force means excellent performance/ output for any organization. At Royal, we ensure that you get the best cover for your staff within your budget, and one that caters for their specific needs. Any company with 7 employees and above can get a corporate cover with the below benefits:\r\n<ul>\r\n<li>Inpatient / hospitalization Cover</li>\r\n<li>Outpatient Cover</li>\r\n<li>Dental</li>\r\n<li>Optical</li>\r\n<li>Maternity</li>\r\n<li>Last Expense</li>\r\n</ul>\r\nTo give a corporate quote we need; name of the organization, no. of employees and benefits you wish to cover them for, and leave the part of negotiating the best premiums to us.\r\n<h2>HEALTH  INSURANCE PRODUCT FOR THE MASS MARKET</h2>\r\nRoyal Associates will soon be launching a very innovative health insurance product that is very affordable for every Kenyan household and has very comprehensive coverage. It’s an inpatient only cover with access to all the major hospitals in Kenya and referrals to India. It will be riding on a digital platform hence eliminating the usual paper work associated with other insurances!\r\nWatch out for <em>ROYALMED</em> Coming soon\r\n", "Health Insurance", "", "publish", "closed", "closed", "", "health-insurance-kenya", "", "", "2017-04-10 01:13:59", "2017-04-09 22:13:59", "", "0", "http://royalassociates.co.ke/?post_type=product&#038;p=769", "0", "product", "", "0");
INSERT INTO `wp_posts` VALUES("771", "1", "2017-04-10 01:13:23", "2017-04-09 22:13:23", "", "Health Insurance", "", "inherit", "open", "closed", "", "health-insurance", "", "", "2017-04-10 01:13:54", "2017-04-09 22:13:54", "", "769", "http://royalassociates.co.ke/wp-content/uploads/2017/04/HEALTH-INSURANCE.jpg", "0", "attachment", "image/jpeg", "0");
INSERT INTO `wp_posts` VALUES("772", "1", "2017-04-10 01:14:12", "2017-04-09 22:14:12", "At Royal Associates Health Division, we work with Individuals, SME’s and corporate employers to develop customized health benefits plans that best suits their specific needs.\r\nAmong Our Health Insurance include:\r\n<h2>Individual/ Family Health Insurance</h2>\r\n\r\nWe value your life as an individual by offering the following covers to take care of your health and that of your family:\r\n<ul>\r\n<li>Inpatient / hospitalization Cover</li>\r\n<li>Outpatient Cover</li>\r\n<li>Dental</li>\r\n<li>Optical</li>\r\n<li>Maternity</li>\r\n<li>Last Expense</li>\r\n</ul>\r\nWe realize that individuals / families have different needs and requirements and we always endeavor to give the most customized covers for our clients.\r\nAll we require to give you the most competitive quotation is your age and that of your dependants\r\n<h2>SMEs\' and Corporate Health Insurance</h2>\r\nA healthy work force means excellent performance/ output for any organization. At Royal, we ensure that you get the best cover for your staff within your budget, and one that caters for their specific needs. Any company with 7 employees and above can get a corporate cover with the below benefits:\r\n<ul>\r\n<li>Inpatient / hospitalization Cover</li>\r\n<li>Outpatient Cover</li>\r\n<li>Dental</li>\r\n<li>Optical</li>\r\n<li>Maternity</li>\r\n<li>Last Expense</li>\r\n</ul>\r\nTo give a corporate quote we need; name of the organization, no. of employees and benefits you wish to cover them for, and leave the part of negotiating the best premiums to us.\r\n<h2>HEALTH  INSURANCE PRODUCT FOR THE MASS MARKET</h2>\r\nRoyal Associates will soon be launching a very innovative health insurance product that is very affordable for every Kenyan household and has very comprehensive coverage. It’s an inpatient only cover with access to all the major hospitals in Kenya and referrals to India. It will be riding on a digital platform hence eliminating the usual paper work associated with other insurances!\r\nWatch out for <em>ROYALMED</em> Coming soon\r\n", "Health Insurance", "", "inherit", "closed", "closed", "", "769-autosave-v1", "", "", "2017-04-10 01:14:12", "2017-04-09 22:14:12", "", "769", "http://royalassociates.co.ke/blog/769-autosave-v1/", "0", "revision", "", "0");
