INSERT INTO `wp_posts` VALUES("777", "1", "2017-05-15 21:39:26", "2017-05-15 18:39:26", "At Royal Associates Insurance, we have a pool of professionals experienced in structuring various policies to cater for various clients’ specific requirements. We do reviews on a regular basis to take advantage of developments in the insurance market as they occur.\n\nWe make appropriate improvements in the scope of cover in order to make our policies cost effective and dispute free in the event of a claim. \nThese includes:\n<ol>\n<li>Restructuring the policies,\n<li>Including all the relevant extensive clauses</li>\n<li>Reviewing the premium rating structure</li>\n</ol>\n \nWe ensure that the warranties applying under each of the policies do not unreasonably prejudice your protection.\n", "Property Insurance", "", "inherit", "closed", "closed", "", "580-autosave-v1", "", "", "2017-05-15 21:39:26", "2017-05-15 18:39:26", "", "580", "http://royalassociates.co.ke/blog/580-autosave-v1/", "0", "revision", "", "0");
